customCSS:
/* Meltdown - Post-Apocalyptic Mining Terminal */
@import url('https://fonts.googleapis.com/css2?family=Special+Elite&family=Courier+Prime:wght@400;700&family=Fira+Code:wght@400;500&display=swap');

/* Irradiated ambient background */
.cyber-grid {
  background:
    repeating-linear-gradient(
      0deg,
      transparent,
      transparent 3px,
      rgba(57, 255, 20, 0.015) 3px,
      rgba(57, 255, 20, 0.015) 6px
    );
  animation: none;
}

.cyber-glow {
  background:
    radial-gradient(ellipse 600px 400px at 20% 15%, rgba(57, 255, 20, 0.04), transparent),
    radial-gradient(ellipse 400px 300px at 80% 80%, rgba(204, 85, 0, 0.03), transparent);
}

/* Radiation scan line */
.scan-line {
  background: linear-gradient(
    to bottom,
    transparent 0%,
    rgba(57, 255, 20, 0.04) 50%,
    transparent 100%
  );
  animation: scanLines 6s linear infinite;
}

/* Corroded/rusted card borders */
.stat-card,
.miner-card,
.health-card,
.lifetime-card {
  border: 1px dashed rgba(200, 169, 81, 0.25);
  border-radius: 4px;
  position: relative;
}

/* Radiation strip on stat cards */
.stat-card::before {
  background: linear-gradient(90deg, #39ff14, #c8a951, #cc5500);
  height: 2px;
  opacity: 0.7;
}

/* Geiger counter glow on hover */
.stat-card:hover,
.miner-card:hover {
  border-color: rgba(57, 255, 20, 0.35);
  box-shadow:
    0 0 12px rgba(57, 255, 20, 0.15),
    inset 0 0 15px rgba(57, 255, 20, 0.03);
}

/* Stat values — radiation green glow */
.stat-value {
  text-shadow: 0 0 10px rgba(57, 255, 20, 0.4);
}

/* Celebration styling */
.celebration-title {
  color: #39ff14 !important;
  text-shadow: 0 0 25px rgba(57, 255, 20, 0.6), 0 0 50px rgba(57, 255, 20, 0.3) !important;
}

.celebration-icon {
  filter: hue-rotate(85deg) brightness(1.2);
}

/* Irradiated logo treatment */
.logo {
  text-shadow: 0 0 15px rgba(57, 255, 20, 0.3);
  letter-spacing: 3px;
}

/* Dust particle styling */
.cyber-particles {
  opacity: 0.3;
}

/* Section headers — rusted accent */
.section-header h2 {
  border-bottom: 1px solid rgba(200, 169, 81, 0.2);
  padding-bottom: 0.5rem;
}

/* Alert badges — warning orange */
.badge {
  border-color: rgba(204, 85, 0, 0.4);
}

/* Scrollbar — corroded colors */
::-webkit-scrollbar-thumb {
  background: rgba(200, 169, 81, 0.3);
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(200, 169, 81, 0.5);
}
